// filterItemAriaLabel returns the accessible label string for the current state.
func filterItemAriaLabel(state, label string) string {
	switch state {
	case "include":
		return "Include " + label + " (click to exclude)"
	case "exclude":
		return "Exclude " + label + " (click to clear)"
	default:
		return "Any " + label + " (click to include)"
	}
}

